() => {
  const tableMain = document.querySelector('gs-table > main');
  if (!tableMain) return;

  const headerCells = Array.from(tableMain.querySelectorAll(':scope > gs-header-cell-wrapper'));
  if (headerCells.length) {
    headerCells[0].setAttribute('data-capture-head-start', '1');
    headerCells[headerCells.length - 1].setAttribute('data-capture-head-end', '1');
  }

  const actionButtons = Array.from(tableMain.querySelectorAll("button[data-qa-id='scenarioActions']"));
  const targetBtn =
    actionButtons.find((b) => b.getAttribute('aria-controls') === 'cdk-menu-16') ||
    actionButtons.find((b) => b.getAttribute('data-cdk-menu-stack-id') === '545') ||
    actionButtons.find((b) => b.getAttribute('data-cdk-menu-stack-id') === '544') ||
    actionButtons.find((b) => b.getAttribute('aria-expanded') === 'true') ||
    actionButtons[0];

  if (!targetBtn) return;

  // Evidenciar click sobre el boton de los tres puntos.
  targetBtn.style.background = 'rgba(109, 255, 231, 0.16)';
  targetBtn.style.boxShadow = 'inset 0 0 0 1px rgba(109, 255, 231, 0.65)';
  targetBtn.style.borderRadius = '8px';

  const allRowCells = Array.from(tableMain.querySelectorAll(':scope > gs-cell-wrapper'));
  const targetActionCell = targetBtn.closest('gs-cell-wrapper');
  const rowSize = Math.max(1, headerCells.length || 7);

  if (targetActionCell) {
    const idx = allRowCells.indexOf(targetActionCell);
    if (idx >= 0) {
      const rowStart = idx - (idx % rowSize);
      const targetRow = allRowCells.slice(rowStart, rowStart + rowSize);
      if (targetRow.length) {
        targetRow[0].setAttribute('data-capture-row-start', '1');
        targetRow[targetRow.length - 1].setAttribute('data-capture-row-end', '1');
      }

      const keep = new Set(targetRow);
      allRowCells.forEach((cell) => {
        if (!keep.has(cell)) cell.style.display = 'none';
      });
    }
  }

  // Ocultar elementos que no forman parte de la captura requerida.
  document.querySelectorAll('gs-table-paginator, gs-table-selection').forEach((el) => {
    el.style.display = 'none';
  });

  const menu = document.querySelector("gs-menu[role='menu']:has(button[data-qa-id='editScenarioBtn'])");
  if (!menu) return;

  const wrap = menu.closest('.cdk-overlay-connected-position-bounding-box');
  if (wrap) {
    wrap.style.left = '0px';
    wrap.style.top = '0px';
    wrap.style.width = '100vw';
    wrap.style.height = '100vh';
    wrap.style.position = 'fixed';
    wrap.style.display = 'block';
    wrap.style.transform = 'none';
  }

  const pane = menu.closest('.cdk-overlay-pane');
  if (pane) {
    pane.style.position = 'fixed';
    pane.style.transform = 'none';
  }

  // Alinear menu contextual centrado respecto al boton de los 3 puntos.
  const br = targetBtn.getBoundingClientRect();
  const mr = menu.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;
  const margin = 8;

  let left = Math.round(br.right + 10);
  if (left + mr.width > vw - margin) {
    left = Math.round(br.left - mr.width - 10);
  }
  left = Math.max(margin, Math.min(left, vw - mr.width - margin));

  let top = Math.round(br.top + (br.height / 2) - (mr.height / 2));
  top = Math.max(margin, Math.min(top, vh - mr.height - margin));

  const target = pane || menu;
  target.style.left = `${left}px`;
  target.style.top = `${top}px`;
  target.style.right = 'auto';
  target.style.bottom = 'auto';

  // Marcar "Validar" como opcion seleccionada/destacada.
  const validar = Array.from(menu.querySelectorAll("button[role='menuitem']")).find((b) =>
    /Validar/i.test((b.textContent || '').trim())
  );
  if (validar) {
    validar.style.background = 'rgba(109, 255, 231, 0.14)';
    validar.style.outline = '1px solid rgba(109, 255, 231, 0.65)';
    validar.style.borderRadius = '8px';
    validar.style.fontWeight = '600';
  }
}
